<?php $links=json_decode($settings['footer_links_json']??'[]',true)?:[['label'=>'Semua produk','url'=>'/produk'],['label'=>'Keranjang','url'=>'/keranjang']];while(count($links)<5)$links[]=['label'=>'','url'=>''];?><header class="page-head"><div><span class="eyebrow">Tampilan / Footer</span><h1>Footer</h1></div></header><form method="post" action="<?=url('/admin/appearance/footer')?>" class="editor-grid"><?=csrf_field()?><section class="panel stack"><h2>Informasi toko</h2><label class="check"><input type="checkbox" name="footer_show_logo" value="1" <?=($settings['footer_show_logo']??'1')==='1'?'checked':''?>> Tampilkan logo</label><label>Deskripsi<textarea name="footer_description"><?=e($settings['footer_description']??setting('store_tagline'))?></textarea></label><div class="form-grid"><label>Email<input type="email" name="footer_email" value="<?=e($settings['footer_email']??'')?>"></label><label>Jam operasional<input name="footer_hours" value="<?=e($settings['footer_hours']??'')?>"></label></div><h2>Link footer</h2><?php foreach($links as $i=>$link):?><div class="form-grid"><label>Label<input name="links[<?=$i?>][label]" value="<?=e($link['label'])?>"></label><label>URL<input name="links[<?=$i?>][url]" value="<?=e($link['url'])?>"></label></div><?php endforeach?><h2>Media sosial</h2><div class="form-grid"><label>Instagram<input name="footer_instagram" value="<?=e($settings['footer_instagram']??'')?>"></label><label>Facebook<input name="footer_facebook" value="<?=e($settings['footer_facebook']??'')?>"></label><label>TikTok<input name="footer_tiktok" value="<?=e($settings['footer_tiktok']??'')?>"></label><label>YouTube<input name="footer_youtube" value="<?=e($settings['footer_youtube']??'')?>"></label></div></section><aside class="stack"><section class="panel stack"><h2>Susunan dan legal</h2><label>Layout<select name="footer_layout"><option value="two">Dua kolom</option><option value="three" <?=($settings['footer_layout']??'three')==='three'?'selected':''?>>Tiga kolom</option><option value="minimal" <?=($settings['footer_layout']??'')==='minimal'?'selected':''?>>Minimal</option></select></label><label>Copyright<input name="footer_copyright" value="<?=e($settings['footer_copyright']??'© {year} '.setting('store_name').'. Semua hak dilindungi.')?>"><small>{year} diganti otomatis.</small></label><label>URL kebijakan privasi<input name="footer_privacy_url" value="<?=e($settings['footer_privacy_url']??'')?>"></label><label>URL syarat & ketentuan<input name="footer_terms_url" value="<?=e($settings['footer_terms_url']??'')?>"></label><label>URL kebijakan retur<input name="footer_returns_url" value="<?=e($settings['footer_returns_url']??'')?>"></label><label class="check"><input type="checkbox" name="footer_show_powered" value="1" <?=($settings['footer_show_powered']??'1')==='1'?'checked':''?>> Tampilkan “Powered by Zenhosta”</label><button class="button button-large">Simpan footer</button></section></aside></form>
